import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import './Css/Landing.css';

const Landing = () => {
  const navigate = useNavigate();
  const [games, setGames] = useState([]);
  const [showProfile, setShowProfile] = useState(false);

  // Fetch games from PostgreSQL when page loads
  useEffect(() => {
    const fetchGames = async () => {
      try {
        const response = await fetch('http://localhost:8000/api/top-games');
        const data = await response.json();
        if (data.status === 'success') {
          setGames(data.games);
        }
      } catch (error) {
        console.error("Database connection failed", error);
      }
    };
    fetchGames();
  }, []);

  const handleLogout = () => {
    navigate('/'); // Teleport back to login
  };

  const handleWishlist = (gameTitle) => {
    // We will connect this to Python's wishlist table later!
    alert(`Connecting ${gameTitle} to your wishlist soon!`);
  };

  return (
    <div className="landing-container">
      {/* HEADER */}
      <header className="landing-header">
        <div className="logo">GAMING<span>HUB</span></div>

        <nav className="landing-nav">
          <span className="active">Home</span>
          <span>Community</span>
        </nav>

        <div className="search-bar">
          <input type="text" placeholder="Search games..." />
        </div>

        <div className="profile-wrapper" onClick={() => setShowProfile(!showProfile)}>
          <div className="avatar">G</div>

          {/* Dropdown */}
          {showProfile && (
            <div className="profile-dropdown">
              <div className="dropdown-item">Profile</div>
              <div className="dropdown-item">Steam Link</div>
              <div className="dropdown-item logout" onClick={handleLogout}>Logout</div>
            </div>
          )}
        </div>
      </header>

      {/* HERO BANNER */}
      <section className="hero">
        <h1>Welcome to the Grid.</h1>
        <p>Explore the top trending games in the database right now.</p>
      </section>

      {/* GAMES GRID */}
      <section className="games-section">
        <div className="games-grid">
          {games.map((game) => (
            <div key={game.id} className="game-card">
              <img src={game.image} alt={game.title} className="game-img" />
              <div className="game-info">
                <div>
                  <h3>{game.title}</h3>
                  <span className="genre-badge">{game.genre}</span>
                </div>
                {/* The Wishlist Button */}
                <button className="heart-btn" onClick={() => handleWishlist(game.title)}>
                  ♥
                </button>
              </div>
            </div>
          ))}
        </div>
      </section>
    </div>
  );
};

export default Landing;
